import React, { useState, useEffect } from 'react';
import './Settings.css';
import DeleteForeverIcon from '@mui/icons-material/DeleteForever';

const Settings = ({ setDomain, setProject, setIssueType }) => {
  const [isLocked, setIsLocked] = useState(true);
  const [detailsList, setDetailsList] = useState([]);
  const [selectedCredential, setSelectedCredential] = useState(null);

  useEffect(() => {
    fetchDetails();
  }, []);

  const fetchDetails = async () => {
    try {
      const response = await fetch('https://localhost:7216/api/Details');
      if (response.ok) {
        const data = await response.json();
        console.log(data); // Debugging the fetched data
        setDetailsList(data);
      } else {
        console.error('Failed to fetch details:', response.statusText);
      }
    } catch (error) {
      console.error('Error fetching details:', error);
    }
  };

  const handleDelete = async (detail) => {
    try {
      const response = await fetch('https://localhost:7216/api/Details/Delete', {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(detail),
      });

      if (response.ok) {
        setDetailsList(detailsList.filter((d) => d.Domain !== detail.Domain || d.Project !== detail.Project || d.IssueType !== detail.IssueType));
        alert('Credential deleted successfully');
      } else {
        const errorMessage = await response.text();
        console.error('Failed to delete credential:', errorMessage);
      }
    } catch (error) {
      console.error('Error deleting credential:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!selectedCredential) {
      alert('Please select a credential to update or enter a new one.');
      return;
    }

    const newCredential = { Domain: selectedCredential.Domain, Project: selectedCredential.Project, IssueType: selectedCredential.IssueType };

    try {
      const response = await fetch('https://localhost:7216/api/Details/Manage', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newCredential),
      });

      if (response.ok) {
        const { data } = await response.json();
        setDetailsList((prevDetails) => [...prevDetails, data]);
        alert('Credential saved successfully');
      } else {
        const errorMessage = await response.text();
        console.error('Failed to save credential:', errorMessage);
        alert('Failed to save credential');
      }
    } catch (error) {
      console.error('Error saving credential:', error);
      alert('Error saving credential');
    }
  };

  const handleLockToggle = () => {
    setIsLocked(!isLocked);
  };

  const handleLoadCredential = () => {
    if (selectedCredential) {
      setDomain(selectedCredential.Domain);
      setProject(selectedCredential.Project);
      setIssueType(selectedCredential.IssueType);
    }
  };

  const handleSelectCredential = (credential) => {
    setSelectedCredential(credential);
    setIsLocked(false); // Unlock form when a credential is selected
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>

      <h3>Add or Update Credential</h3>
      <form onSubmit={handleSubmit}>
        <div>
          <label>
            Domain:
            <input
              type="text"
              value={selectedCredential?.Domain || ''}
              onChange={(e) => setSelectedCredential({ ...selectedCredential, Domain: e.target.value })}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Project:
            <input
              type="text"
              value={selectedCredential?.Project || ''}
              onChange={(e) => setSelectedCredential({ ...selectedCredential, Project: e.target.value })}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Issue Type:
            <input
              type="text"
              value={selectedCredential?.IssueType || ''}
              onChange={(e) => setSelectedCredential({ ...selectedCredential, IssueType: e.target.value })}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            <input
              type="checkbox"
              checked={!isLocked}
              onChange={handleLockToggle}
            />
            Unlock to Edit
          </label>
        </div>
        <div>
          <button type="submit" disabled={isLocked}>Save</button>
          <button type="button" onClick={handleLoadCredential} disabled={isLocked || !selectedCredential}>Load</button>
        </div>
      </form>

      <div className="details-list">
        <h3>Saved Credentials</h3>
        <table className="details-table">
          <thead>
            <tr>
              <th>Domain</th>
              <th>Project</th>
              <th>Issue Type</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {detailsList.length > 0 ? (
              detailsList.map((detail) => (
                <tr key={`${detail.Domain}-${detail.Project}-${detail.IssueType}`} onClick={() => handleSelectCredential(detail)}>
                  <td>{detail.Domain}</td>
                  <td>{detail.Project}</td>
                  <td>{detail.IssueType}</td>
                  <td>
                    <DeleteForeverIcon
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDelete(detail);
                      }}
                      style={{ cursor: 'pointer', color: 'red' }}
                    />
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="4">No credentials available</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Settings;
